+    table[constants.NOP] = .{ .name = "NOP", .stack_effect = 0, .flags = 0 };
+    table[constants.POP_TOP] = .{ .name = "POP_TOP", .stack_effect = -1, .flags = 0 };
+    table[constants.PUSH_NULL] = .{ .name = "PUSH_NULL", .stack_effect = 1, .flags = 0 };
