+    if (pos + 1 < bytecode.len) {
+        arg |= bytecode[pos + 1];
+    }
+
+    return .{
+        .opcode = bytecode[pos],
+        .arg = arg,
+        .next_offset = pos + 2 + @as(usize, metadata.cacheEntries(bytecode[pos])) * 2,
+    };
