+/// Deinitialize cache completely (call at shutdown)
+pub fn deinitCache() void {
+    cache_mutex.lock();
+    defer cache_mutex.unlock();
+
+    if (lru_cache) |*cache| {
+        cache.deinit();
+        lru_cache = null;
+        cache_allocator = null;
+    }
