+    if (std.mem.eql(u8, s, "-inf") or std.mem.eql(u8, s, "-Infinity")) {
+        return -std.math.inf(f64);
+    }
+    if (std.mem.eql(u8, s, "nan") or std.mem.eql(u8, s, "NaN")) {
