+    var buf: [256]u8 = undefined;
+    var len: usize = 0;
+    for (num_part) |c| {
+        if (c != '_') {
+            if (len >= buf.len) return null;
+            buf[len] = c;
+            len += 1;
+        }
+    }
+    if (len == 0) return null;
+
+    const value = std.fmt.parseInt(i64, buf[0..len], base) catch return null;
+    return if (negative) -value else value;
+}
