+        // Internal
+        // ====================================================================
+
+        fn shouldGrow(self: Self) bool {
+            return self.loadFactor() > constants.MAX_LOAD_FACTOR;
+        }
+
+        fn shouldShrink(self: Self) bool {
+            return self.capacity > constants.MIN_SIZE and self.loadFactor() < constants.MIN_LOAD_FACTOR;
+        }
