+            // Rehash all entries
+            for (old_buckets) |bucket| {
+                var entry = bucket;
+                while (entry) |e| {
+                    const next_entry = e.next;
+                    const idx = e.hash & (new_capacity - 1);
+
+                    e.next = self.buckets[idx];
+                    self.buckets[idx] = e;
+
+                    entry = next_entry;
+                }
+            }
