+                const bytes = std.mem.asBytes(&key);
+                return hash_functions.fnvHash(bytes);
+            }
+        }
+
+        fn keysEqual(a: K, b: K) bool {
+            if (K == []const u8) {
+                return std.mem.eql(u8, a, b);
+            } else {
+                return a == b;
+            }
+        }
+    };
+}

